// ── v5.5 Excel template (base64) ──────────────────────────────────────────
// Acquisition_Model_Final_v5_5.xlsx — populated client-side via SheetJS
const V55_TEMPLATE_B64 = "";

function b64ToUint8Array(b64){
  const bin = atob(b64);
  const len = bin.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

// Budget row layout (must mirror populate_v55.py)
const V55_CATEGORIES_ORDER = [
  "Demolition","Structural","Roofing","MEP (Mechanical, Electrical, Plumbing)",
  "Interior Build-Out","Flooring","Finishes","Cabinets & Countertops",
  "Fixtures","Appliances","Exterior"
];
const V55_ITEMS_PER_CAT = 5;
function v55CatStartRow(catIdx){ return 12 + catIdx * 8 + 1; }

// Write a single cell into a SheetJS sheet, preserving any existing format
// ExcelJS writes to cells via `cell.value = v` which preserves all existing styling.
// Unlike our previous XLSX helper, it handles nulls/empties uniformly without a type flag.
function v55WriteCell(ws, addr, value /*, type (unused) */){
  if (!ws) return;
  const cell = ws.getCell(addr);
  if (value === null || value === undefined || value === "") {
    cell.value = null;
    return;
  }
  cell.value = value;
}

async function v55Populate(payload){
  const buf = b64ToUint8Array(V55_TEMPLATE_B64);
  const wb = new ExcelJS.Workbook();
  await wb.xlsx.load(buf);

  const a = payload.assumptions;
  const ws = wb.getWorksheet("Assumptions");

  // Property
  v55WriteCell(ws,"C4",a.address,"s");
  v55WriteCell(ws,"C5",a.cityState,"s");
  v55WriteCell(ws,"C6",String(a.zip||""),"s");
  v55WriteCell(ws,"C7",Number(a.units)||1,"n");
  v55WriteCell(ws,"C8",Number(a.sqft)||0,"n");
  v55WriteCell(ws,"C9",a.yearBuilt?String(a.yearBuilt):"","s");
  v55WriteCell(ws,"C10",a.floodZone||"X","s");
  v55WriteCell(ws,"C11",Number(a.landSF)||0,"n");
  v55WriteCell(ws,"C12",a.propertyType||"SFR","s");
  v55WriteCell(ws,"C13",a.dealSourcing||"","s");
  v55WriteCell(ws,"C15",Number(a.acquisitionPrice)||0,"n");
  v55WriteCell(ws,"C16",Number(a.arv)||0,"n");
  v55WriteCell(ws,"C17",Number(a.annualTaxes)||0,"n");

  // Bridge matrix
  const bridge = a.bridge || {};
  const lenders = bridge.lenders || [];
  const bandCols = [["D","E","F"],["G","H","I"],["J","K","L"]];
  for (let li=0; li<Math.min(3, lenders.length); li++){
    const cols = bandCols[li];
    const lender = lenders[li];
    for (let bi=0; bi<Math.min(3, (lender.bands||[]).length); bi++){
      const col = cols[bi];
      const band = lender.bands[bi];
      if (bi === 0) v55WriteCell(ws,`${col}21`,lender.name||"","s");
      v55WriteCell(ws,`${col}22`,Number(band.ltc)||0,"n");
      v55WriteCell(ws,`${col}23`,Number(band.ltv)||0,"n");
      v55WriteCell(ws,`${col}24`,Number(band.orig)||0,"n");
      v55WriteCell(ws,`${col}25`,Number(band.rate)||0,"n");
      v55WriteCell(ws,`${col}27`,Number(band.rate)||0,"n");
    }
  }
  v55WriteCell(ws,"C29",bridge.useBridge||"Yes","s");
  v55WriteCell(ws,"C30",Number(bridge.selectedLender)||1,"n");
  v55WriteCell(ws,"C31",Number(bridge.selectedBand)||2,"n");
  v55WriteCell(ws,"C32",Number(bridge.projectDuration)||6,"n");

  // Closing costs
  const cc = a.closingCosts || {};
  v55WriteCell(ws,"C33",Number(cc.processingFee)||999,"n");
  v55WriteCell(ws,"C41",Number(cc.appraisal)||0,"n");
  v55WriteCell(ws,"C42",Number(cc.inspection)||485,"n");
  v55WriteCell(ws,"C43",Number(cc.lenderLegal)||0,"n");
  v55WriteCell(ws,"C44",Number(cc.processingFee)||999,"n");
  v55WriteCell(ws,"C45",Number(cc.miscClosing)||0,"n");
  v55WriteCell(ws,"C46",Number(cc.titleBridge)||3500,"n");
  v55WriteCell(ws,"C47",Number(cc.titleNoBridge)||1500,"n");
  v55WriteCell(ws,"C48",Number(cc.floodInsurance)||0,"n");
  v55WriteCell(ws,"C49",Number(cc.insurance12Mo)||1600,"n");

  // Operating
  const op = a.operating || {};
  v55WriteCell(ws,"C55",Number(op.waterSewerPerUnit)||0,"n");
  v55WriteCell(ws,"C56",Number(op.repairsPerUnit)||75,"n");
  v55WriteCell(ws,"C57",Number(op.mgmtPct)||0.10,"n");
  // Misc Op Ex lands in C58 if that row exists in the template
  v55WriteCell(ws,"C58",Number(op.miscOpEx)||0);

  // Exit
  const ex = a.exit || {};
  v55WriteCell(ws,"C61",Number(ex.addlMonthsInterest)||3,"n");
  v55WriteCell(ws,"C62",Number(ex.concessionPct)||0,"n");
  v55WriteCell(ws,"C63",Number(ex.brokerFeePct)||0.025,"n");
  v55WriteCell(ws,"C64",Number(ex.selectedDSCRLender)||1,"n");

  // Partnership
  const p = a.partnership || {};
  v55WriteCell(ws,"C67",p.capitalSource||"Sponsor","s");
  v55WriteCell(ws,"C69",p.partner1Name||"Boris","s");
  v55WriteCell(ws,"C70",p.partner2Name||"Jon","s");
  v55WriteCell(ws,"C71",Number(p.outsideSplit)||0.5,"n");
  v55WriteCell(ws,"C72",1-(Number(p.outsideSplit)||0.5),"n");
  v55WriteCell(ws,"C73",Number(p.sponsorPreB)||0.80,"n");
  v55WriteCell(ws,"C74",Number(p.sponsorPreJ)||0.20,"n");
  v55WriteCell(ws,"C75",Number(p.sponsorPostB)||0.70,"n");
  v55WriteCell(ws,"C76",Number(p.sponsorPostJ)||0.30,"n");

  // ── Budget ──
  const bws = wb.getWorksheet("Budget");
  const b = payload.budget || {};
  v55WriteCell(bws,"C8",Number(b.contingencyPct)||0.15,"n");
  v55WriteCell(bws,"G8",Number(b.laborBudget)||0,"n");
  v55WriteCell(bws,"C9",Number(b.laborActual)||0,"n");

  // Build category lookup (case-insensitive)
  const catLookup = {};
  (b.categories || []).forEach(cat => {
    const key = (cat.category || "").trim().toLowerCase();
    catLookup[key] = cat;
  });

  V55_CATEGORIES_ORDER.forEach((expectedName, catIdx) => {
    const key = expectedName.trim().toLowerCase();
    const cat = catLookup[key];
    if (!cat) return;
    const items = (cat.items || []).slice(0, V55_ITEMS_PER_CAT);
    const firstRow = v55CatStartRow(catIdx);
    // Clear all 5 slots first
    for (let i=0; i<V55_ITEMS_PER_CAT; i++){
      const r = firstRow + i;
      v55WriteCell(bws,`A${r}`,"","s");
      v55WriteCell(bws,`B${r}`,"","s");
      v55WriteCell(bws,`C${r}`,0,"n");
      v55WriteCell(bws,`D${r}`,0,"n");
      v55WriteCell(bws,`F${r}`,0,"n");
    }
    items.forEach((item, i) => {
      const r = firstRow + i;
      v55WriteCell(bws,`A${r}`,item.item||"","s");
      v55WriteCell(bws,`B${r}`,item.location||"","s");
      v55WriteCell(bws,`C${r}`,Number(item.unitCost)||0,"n");
      v55WriteCell(bws,`D${r}`,Number(item.qty)||0,"n");
      if (item.actual) v55WriteCell(bws,`F${r}`,Number(item.actual)||0,"n");
    });
  });

  // ── Rent Roll ──
  const rws = wb.getWorksheet("Rent Roll");
  // Clear rows 4-7
  for (let r=4; r<=7; r++){
    ["B","C","D","E","F","G"].forEach(col => v55WriteCell(rws,`${col}${r}`,"","s"));
  }
  (payload.rentRoll || []).slice(0,4).forEach((unit, i) => {
    const r = 4 + i;
    v55WriteCell(rws,`B${r}`,unit.unit||String(i+1),"s");
    v55WriteCell(rws,`C${r}`,Number(unit.beds)||1,"n");
    v55WriteCell(rws,`D${r}`,Number(unit.baths)||1,"n");
    v55WriteCell(rws,`E${r}`,Number(unit.currentRent)||0,"n");
    v55WriteCell(rws,`F${r}`,Number(unit.projectedRent)||0,"n");
    if (unit.leaseExp) v55WriteCell(rws,`G${r}`,unit.leaseExp,"s");
  });

  // ── Comparables ──
  const cws = wb.getWorksheet("Comparables");
  // Clear rows 4-8 (cols A-O)
  for (let r=4; r<=8; r++){
    ["A","B","C","D","E","F","G","H","I","J","K","L","M","N","O"].forEach(col => {
      v55WriteCell(cws,`${col}${r}`,"","s");
    });
  }
  (payload.comparables || []).slice(0,5).forEach((cp, i) => {
    const r = 4 + i;
    v55WriteCell(cws,`A${r}`,cp.link||"","s");
    v55WriteCell(cws,`B${r}`,cp.address||"","s");
    v55WriteCell(cws,`C${r}`,cp.city||"Baton Rouge","s");
    v55WriteCell(cws,`D${r}`,cp.state||"LA","s");
    v55WriteCell(cws,`E${r}`,String(cp.zip||""),"s");
    v55WriteCell(cws,`F${r}`,Number(cp.distance)||0,"n");
    if (cp.salePrice) v55WriteCell(cws,`G${r}`,Number(cp.salePrice),"n");
    if (cp.saleDate) v55WriteCell(cws,`H${r}`,cp.saleDate,"s");
    if (cp.listPrice) v55WriteCell(cws,`I${r}`,Number(cp.listPrice),"n");
    if (cp.listDate) v55WriteCell(cws,`J${r}`,cp.listDate,"s");
    v55WriteCell(cws,`K${r}`,Number(cp.beds)||0,"n");
    v55WriteCell(cws,`L${r}`,Number(cp.baths)||0,"n");
    v55WriteCell(cws,`M${r}`,Number(cp.sqft)||0,"n");
    v55WriteCell(cws,`N${r}`,Number(cp.lotSF)||0,"n");
  });

  // Force formula recalc on open — ExcelJS preserves the calcPr element from the template.
  // Explicitly set calcProperties so stale cached values get recomputed when Excel opens the file.
  if (wb.calcProperties) wb.calcProperties.fullCalcOnLoad = true;

  return await wb.xlsx.writeBuffer();
}

async function v55Download(payload, filename){
  const buf = await v55Populate(payload);
  const blob = new Blob([buf], {type:"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"});
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

