// ── Calc engine ────────────────────────────────────────────────────────────
function PMT(rate,n,pv){if(!rate||!n||!pv)return 0;return pv*(rate*Math.pow(1+rate,n))/(Math.pow(1+rate,n)-1);}
function computeAll(i){
  const matSub=i.budget.reduce((s,c)=>s+c.items.reduce((ss,it)=>ss+num(it.uc)*num(it.qty),0),0);
  const labB=num(i.laborBudget),contAmt=(matSub+labB)*num(i.contingencyPct);
  const constr=matSub+labB+contAmt;
  const li=Math.min(i.bridgeMatrix.length-1,Math.max(0,num(i.selectedLender)-1));
  const bi=Math.min((i.bridgeMatrix[li]?.bands.length||1)-1,Math.max(0,num(i.selectedBand)-1));
  const ab=i.bridgeMatrix[li].bands[bi];
  const acq=num(i.acquisitionPrice),arv=num(i.arv);
  const pLoan=i.useBridge?Math.min((acq+constr)*ab.ltc,arv*ab.ltv):0;
  const finFees=i.useBridge?pLoan*ab.orig:0;
  const intCost=i.useBridge?pLoan*ab.rate/12*num(i.projectDuration):0;
  const cEscrow=i.useBridge?constr:0,debtClose=pLoan-cEscrow;
  const pFee=i.useBridge?num(i.processingFee):0;
  const title=i.useBridge?num(i.titleBridge):num(i.titleNoBridge);
  const cc=num(i.appraisal)+num(i.inspection)+num(i.lenderLegal)+pFee+num(i.miscClosing)+title+num(i.floodInsurance)+num(i.insurance12Mo)+num(i.annualTaxes);
  const tcb=acq+constr+cc+num(i.miscOther)+finFees+intCost;
  const cashReq=i.useBridge?(tcb-constr)-debtClose-intCost:tcb;
  const intRes=intCost,totalCash=cashReq+intRes;
  const mRent=i.rentRoll.reduce((s,u)=>s+num(u.projRent),0);
  const aRents=mRent*12,units=Math.max(1,num(i.units));
  const opTax=num(i.annualTaxes),opIns=num(i.insurance12Mo)+num(i.floodInsurance);
  const opWS=num(i.waterSewerPerUnit)*units*12,opRep=num(i.repairsPerUnit)*units*12;
  const opMgmt=num(i.mgmtPct)*aRents,opMisc=num(i.miscOpEx);
  const totOpEx=opTax+opIns+opWS+opRep+opMgmt+opMisc;
  const noi=aRents-totOpEx,yoc=tcb>0?noi/tcb:0;
  const dscrExits=i.dscrLenders.map((ld,idx)=>{
    const loan=num(ld.ltv)*arv;
    const origA=idx===0?Math.max(2000,num(ld.orig)*loan):num(ld.orig)*loan;
    const slf=idx===1?(loan<125000?1500:0):0;
    const tcc=origA+num(ld.servicingFee)+slf+num(ld.appraisal)+num(ld.thirdParty)+num(ld.title);
    const mPmt=PMT(num(ld.rate)/12,num(ld.amort)*12,loan);
    const aPmt=mPmt*12,dscr=aPmt>0?noi/aPmt:0;
    const co=loan-tcc-pLoan,remEq=Math.max(0,totalCash-co);
    const ancf=noi-aPmt,roe=remEq>0?ancf/remEq:0,ytr=ancf>0?remEq/ancf:null;
    return {name:ld.name,ltv:ld.ltv,rate:ld.rate,amort:ld.amort,loan,origA,slf,servicingFee:num(ld.servicingFee),appraisal:num(ld.appraisal),thirdParty:num(ld.thirdParty),title:num(ld.title),tcc,mPmt,aPmt,dscr,co,remEq,ancf,roe,ytr,ok:dscr>=1.25};
  });
  const sel=dscrExits[Math.min(dscrExits.length-1,Math.max(0,num(i.selectedDSCRLender)-1))];
  const sp=num(i.flipSalePrice)||arv;
  const addlI=i.useBridge?num(i.addlMonthsInterest)*(pLoan*ab.rate/12):0;
  const conc=num(i.concessionPct)*sp,bkrF=num(i.brokerFeePct)*sp;
  const nsp=sp-addlI-conc-bkrF,bpOff=i.useBridge?pLoan:0;
  const fnp=nsp-bpOff,profit=nsp-tcb,froe=totalCash>0?profit/totalCash:0;
  let wf={};const capInv=totalCash;
  if(i.capitalSource==="Outside"){
    const sp50=num(i.outsideSplit)||.5;
    const dRet=-Math.min(Math.max(0,sel.co),capInv),dPro=sel.co+dRet;
    const wfD={np:sel.co,ret:dRet,profit:dPro,b:dPro*sp50,j:dPro*(1-sp50),ncfB:sel.ancf*sp50,ncfJ:sel.ancf*(1-sp50)};
    wfD.var=Math.round(sel.co+wfD.ret-wfD.b-wfD.j);
    const fRet=-Math.min(Math.max(0,fnp),capInv),fPro=fnp+fRet;
    const wfF={gross:nsp,bp:-bpOff,np:fnp,ret:fRet,profit:fPro,b:fPro*sp50,j:fPro*(1-sp50)};
    wfF.var=Math.round(fnp+wfF.ret-wfF.b-wfF.j);
    wf={type:"Outside",d:wfD,f:wfF};
  } else {
    // SPONSOR mode — Boris is sole equity contributor
    // DSCR Refi waterfall:
    //   Net Proceeds at Refi = sel.co (DSCR loan - closing - bridge payoff)
    //   Step 1: Return Boris's capital up to capInv
    //   Step 2: If fully recouped → remaining splits 70/30 (post-return)
    //           Else → equity trap, NCF splits 80/20 (pre-return)
    const borCap=capInv;
    const netProc=sel.co;
    const dRec=netProc>=borCap;
    // Tier 1: return of Boris capital (capped at netProc)
    const dT1Boris=Math.min(netProc,borCap);
    // Tier 2: remaining proceeds split 70/30
    const dT2=Math.max(0,netProc-borCap);
    const postB=num(i.sponsorPostB)||.70;
    const postJ=num(i.sponsorPostJ)||.30;
    const preB=num(i.sponsorPreB)||.80;
    const preJ=num(i.sponsorPreJ)||.20;
    const dT2Boris=dT2*postB;
    const dT2Jon=dT2*postJ;
    const dB=dT1Boris+dT2Boris;
    const dJ=dT2Jon;
    // NCF split: 70/30 if recouped, 80/20 if trapped
    const ncfBPct=dRec?postB:preB;
    const ncfJPct=dRec?postJ:preJ;
    const equityGap=dRec?0:borCap-netProc;
    const wfD={
      netProc,borCap,rec:dRec,
      t1Boris:dT1Boris,t2:dT2,t2Boris:dT2Boris,t2Jon:dT2Jon,
      b:dB,j:dJ,gap:equityGap,
      ncfBPct,ncfJPct,
      ncfB:sel.ancf*ncfBPct,ncfJ:sel.ancf*ncfJPct,
    };
    wfD.var=Math.round(netProc-dB-dJ);
    // FLIP waterfall (unchanged): Tier 1 = return of capital from net flip proceeds, Tier 2 = profit split
    const t1=Math.min(fnp,borCap),t2=Math.max(0,fnp-borCap);
    const fB=t1+t2*postB,fJ=t2*postJ;
    const wfF={gross:nsp,bp:-bpOff,np:fnp,borCap,t1,t2,b:fB,j:fJ};
    wfF.var=Math.round(fnp-fB-fJ);
    wf={type:"Sponsor",d:wfD,f:wfF};
  }
  return {constr,matSub,contAmt,pLoan,finFees,intCost,cEscrow,debtClose,ltcAch:(acq+constr)>0?pLoan/(acq+constr):0,ltvAch:arv>0?pLoan/arv:0,cc,tcb,cashReq,intRes,totalCash,mRent,aRents,opTax,opIns,opWS,opRep,opMgmt,opMisc,totOpEx,noi,yoc,dscrExits,sel,sp,addlI,conc,bkrF,nsp,bpOff,fnp,profit,froe,wf,capInv,ab,li,bi};
}

