// ── Geocoding via Claude API ───────────────────────────────────────────────
// Calls Claude with web_search tool to resolve a street address → {lat, lng}.
// Returns a Promise resolving to {ok:bool, lat, lng, error}.
// Nominatim (OpenStreetMap) geocoder — no API key, free, rate-limited to 1 req/s per their ToS.
// Default viewbox biased to Louisiana / Gulf Coast but will still return hits anywhere in the US.
async function nominatimSearch(q,limit=5){
  if(!q||!q.trim())return [];
  const url=`https://nominatim.openstreetmap.org/search?format=json&addressdetails=1&limit=${limit}&countrycodes=us&q=${encodeURIComponent(q)}`;
  try{
    const resp=await fetch(url,{headers:{"Accept":"application/json"}});
    if(!resp.ok)return [];
    const data=await resp.json();
    return data.map(d=>{
      const a=d.address||{};
      const houseNum=a.house_number||"";
      const road=a.road||a.pedestrian||a.residential||"";
      const street=[houseNum,road].filter(Boolean).join(" ").trim();
      const city=a.city||a.town||a.village||a.hamlet||a.suburb||a.county||"";
      const state=a.state_code||a.state||"";
      const zip=a.postcode||"";
      return {display:d.display_name,street,city,state:state.length===2?state:(state==="Louisiana"?"LA":state),zip,lat:Number(d.lat),lng:Number(d.lon)};
    });
  }catch(e){return [];}
}

async function geocodeAddress(addr){
  if(!addr||!addr.trim())return {ok:false,error:"empty address"};
  const results=await nominatimSearch(addr,1);
  if(!results.length)return {ok:false,error:"no match found for: "+addr};
  const r=results[0];
  if(!isFinite(r.lat)||!isFinite(r.lng))return {ok:false,error:"invalid coords returned"};
  if(r.lat<24||r.lat>50||r.lng<-130||r.lng>-65)return {ok:false,error:`coords outside US: ${r.lat},${r.lng}`};
  return {ok:true,lat:r.lat,lng:r.lng,confidence:"high",display:r.display};
}

function fullAddr(d){
  const parts=[d.address,d.city||"Baton Rouge",d.state||"LA",d.zip].filter(Boolean);
  return parts.join(", ");
}

// Sync key fields from UW model state (uwInputs) and computed values (c) back to outer deal record.
// Called when user clicks Save in the UW modal — keeps Pipeline / Table / Map cards in sync with underwriting.
function syncUWToDeal(deal,i,c){
  const arvVal=num(i.arv);
  return {
    ...deal,
    // Property identity
    address:i.address||deal.address,
    city:i.city||deal.city||"Baton Rouge",
    state:i.state||deal.state||"LA",
    zip:i.zip||deal.zip,
    property_type:i.propertyType||deal.property_type,
    units:num(i.units)||deal.units,
    sqft:num(i.sqft)||deal.sqft,
    flood_zone:i.floodZone||deal.flood_zone,
    source:i.dealSource||deal.source,
    // Acquisition financials
    // Authoritative writes — no "|| deal.foo" fallbacks, because `0` is a legitimate
    // value and JS's falsy coercion would silently resurrect a stale previous value.
    purchase_price:num(i.acquisitionPrice),
    rehab_budget:Math.round(num(c.constr)),
    est_arv:arvVal||deal.est_arv,
    // Full Uses buckets — ensures Sources & Uses tie at the analytics level
    use_purchase:Math.round(num(i.acquisitionPrice)),
    use_rehab:Math.round(num(c.constr)),
    // Everything beyond purchase + rehab: closing costs + financing fees + interest reserve + misc
    use_closing:Math.round(num(c.tcb)-num(i.acquisitionPrice)-num(c.constr)),
    tcb:Math.round(num(c.tcb)),
    // Capital structure
    capital_type:i.capitalSource==="Outside"?"Outside Capital":"Sponsor Capital",
    // Cash-to-close flows into src_equity for Sponsor mode, src_outside for Outside mode —
    // never both. This ensures Sources (equity + debt + OC) ties to TCB.
    src_equity:i.capitalSource==="Outside"?0:Math.round(num(c.totalCash)),
    src_debt:Math.round(num(c.pLoan)),
    src_outside:i.capitalSource==="Outside"?Math.round(num(c.totalCash)):0,
    // Computed outputs from underwriting. These are authoritative writes — if the
    // value is 0 (e.g. no bridge, no rent, DSCR=0), we save exactly that. Old
    // `|| deal.foo` fallbacks silently resurrected stale values due to JS's
    // truthy/falsy coercion of 0.
    flip_profit:Math.round(num(c.profit)),
    flip_roi:c.froe!=null?Number((c.froe*100).toFixed(1)):0,
    exit_dscr:c.sel&&c.sel.dscr!=null?Number(c.sel.dscr.toFixed(2)):0,
    cash_out:Math.round(num(c.sel?.co)),
    monthly_income:Math.round(num(c.mRent)),
    // Per-sf / per-bed cost benchmarks
    cost_per_sf:i.sqft&&c.constr?Number((num(c.constr)/num(i.sqft)).toFixed(2)):deal.cost_per_sf,
    // Clear draft flag on save
    isDraft:false,
  };
}

// ── Leaflet loader hook ────────────────────────────────────────────────────
// Loads Leaflet JS + CSS from cdnjs and resolves once window.L is available.
let _leafletPromise=null;
function loadLeaflet(){
  if(_leafletPromise)return _leafletPromise;
  if(typeof window!=="undefined"&&window.L)return Promise.resolve(window.L);
  _leafletPromise=new Promise((resolve,reject)=>{
    // CSS
    if(!document.querySelector('link[data-leaflet]')){
      const link=document.createElement("link");
      link.rel="stylesheet";
      link.href="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";
      link.setAttribute("data-leaflet","1");
      document.head.appendChild(link);
    }
    // JS
    if(window.L)return resolve(window.L);
    const s=document.createElement("script");
    s.src="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";
    s.onload=()=>resolve(window.L);
    s.onerror=()=>reject(new Error("Failed to load Leaflet"));
    document.head.appendChild(s);
  });
  return _leafletPromise;
}

